#include<bits/stdc++.h>
using namespace std;
const long long N=300010;
long long n,q,val[N],val1[N],top[N],dfn[N],dfncnt,fa[N],siz[N],rnk[N],son[N],d[N];
vector<pair<long long,long long>> mp[N];
void dfs1(long long x,long long f=0)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            d[v]=d[x]+1;
            ::val[v]=(::val[x])^val;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
            val1[v]=val;
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto i:mp[x])
        {
            long long v=i.first;
            if(v!=fa[x]&&v!=son[x])
            {
                dfs2(v,v);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sum0[10],sum1[10],ans,tag;
    }t[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node ls,node rs)
    {
        x.ans=ls.ans+rs.ans;
        for(long long i=0;i<10;i++)
        {
            x.sum0[i]=ls.sum0[i]+rs.sum0[i];
            x.sum1[i]=ls.sum1[i]+rs.sum1[i];
            x.ans+=ls.sum0[i]*rs.sum1[i]*(1<<i);
            x.ans+=ls.sum1[i]*rs.sum0[i]*(1<<i);
        }
    }
    void pushup(long long x)
    {
        pushup(t[x],t[t[x].lson],t[t[x].rson]);
    }
    void pushupd(long long x,long long v)
    {
        for(long long i=0;i<10;i++)
        {
            if(v&(1<<i))
            {
                swap(t[x].sum0[i],t[x].sum1[i]);
            }
        }
        t[x].tag^=v;
    }
    void pushdown(long long x)
    {
        if(t[x].tag!=0)
        {
            pushupd(t[x].lson,t[x].tag);
            pushupd(t[x].rson,t[x].tag);
            t[x].tag=0;
        }
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        t[x].tag=0;
        if(l==r)
        {
            for(long long i=0;i<10;i++)
            {
                if(val[rnk[l]]&(1<<i))
                {
                    t[x].sum0[i]=0;
                    t[x].sum1[i]=1;
                }
                else
                {
                    t[x].sum0[i]=1;
                    t[x].sum1[i]=0;
                }
            }
            t[x].ans=0;
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long v)
    {
        if(t[x].l>r||t[x].r<l)
        {
            return;
        }
        if(l<=t[x].l&&t[x].r<=r)
        {
            pushupd(x,v);
            return;
        }
        pushdown(x);
        update(t[x].lson,l,r,v);
        update(t[x].rson,l,r,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        pushdown(x);
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
segment_tree::node merge(segment_tree::node a,segment_tree::node b)
{
    if(a.l==-1)
    {
        return b;
    }
    if(b.l==-1)
    {
        return a;
    }
    auto ans=a;
    t.pushup(ans,a,b);
    return ans;
}
segment_tree::node query(long long x,long long y)
{
    segment_tree::node ansl,ansr;
    ansl.l=ansr.l=-1;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            ansr=merge(t.query(1,dfn[top[y]],dfn[y]),ansr);
            y=fa[top[y]];
        }
        else
        {
            ansl=merge(ansl,t.query(1,dfn[top[x]],dfn[x]));
            x=fa[top[x]];
        }
    }
    if(d[x]>d[y])
    {
        ansr=merge(t.query(1,dfn[y],dfn[x]),ansr);
    }
    else
    {
        ansl=merge(ansl,t.query(1,dfn[x],dfn[y]));
    }
    return merge(ansl,ansr);
}
map<pair<long long,long long>,long long> mp1;
long long U[N],V[N],W[N];
int main()
{
    scanf("%lld%lld",&n,&q);
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        U[i]=u,V[i]=v,W[i]=w;
        mp1[{u,v}]=mp1[{v,u}]=i;
        mp[u].push_back({v,w});
        mp[v].push_back({u,w});
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,n);
    while(q--)
    {
        long long op,u,v,w;
        scanf("%lld%lld%lld",&op,&u,&v);
        if(op==1)
        {
            printf("%lld\n",query(u,v).ans);
        }
        else
        {
            scanf("%lld",&w);
            long long now=V[mp1[{u,v}]];
            if(d[U[mp1[{u,v}]]]>d[V[mp1[{u,v}]]])
            {
                now=U[mp1[{u,v}]];
            }
            t.update(1,dfn[now],dfn[now]+siz[now]-1,w^val1[now]);
            val1[now]=w;
        }
    }
    return 0;
}
